import itertools
class Solution:
    def maxStability(self, n, edges, k):
        m = len(edges)
        mand = [i for i in range(m) if edges[i][3] == 1]
        best = -1
        if n - 1 < 0:
            return -1
        if n - 1 > m:
            return -1
        for combo in itertools.combinations(range(m), n - 1):
            sset = set(combo)
            if any(mi not in sset for mi in mand):
                continue
            par = list(range(n))
            def find(x):
                while par[x] != x:
                    par[x] = par[par[x]]
                    x = par[x]
                return x
            ok = True
            for ei in combo:
                u, v = edges[ei][0], edges[ei][1]
                ru, rv = find(u), find(v)
                if ru == rv:
                    ok = False
                    break
                par[ru] = rv
            if not ok:
                continue
            if len(set(find(i) for i in range(n))) != 1:
                continue
            opt = [ei for ei in combo if edges[ei][3] == 0]
            tree_best = -1
            for up in range(0, min(k, len(opt)) + 1):
                for upset in itertools.combinations(opt, up):
                    ups = set(upset)
                    mn = min((edges[ei][2] * 2 if ei in ups else edges[ei][2]) for ei in combo)
                    if mn > tree_best:
                        tree_best = mn
            best = max(best, tree_best)
        return best

