            par = list(range(n))
            def find(x):
                while par[x] != x:
                    par[x] = par[par[x]]
                    x = par[x]
                return x
            comps = n
            for u, v, s, mst in edges:
                if mst == 1:
                    if s < X:
                        return False
                    ru, rv = find(u), find(v)
                    if ru == rv:
                        return False
                    par[ru] = rv
                    comps -= 1
            for u, v, s, mst in edges:
                if mst == 0 and s >= X:
                    ru, rv = find(u), find(v)
                    if ru != rv:
                        par[ru] = rv
                        comps -= 1
            cost = 0
            for u, v, s, mst in edges:
                if mst == 0 and s < X and 2 * s >= X:
                    ru, rv = find(u), find(v)
                    if ru != rv:
                        par[ru] = rv
                        comps -= 1
                        cost += 1
            return comps == 1 and cost <= k
        cands = set([1])
        for u, v, s, mst in edges:
            cands.add(s)
            cands.add(2 * s)
        cands = sorted(cands)
        best = -1
        lo, hi = 0, len(cands) - 1
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(cands[mid]):
                best = cands[mid]
                lo = mid + 1
            else:
