var maxStability = function(n, edges, k) {
    const feasible = (X) => {
        const par = Array.from({length: n}, (_, i) => i);
        const find = (x) => { while (par[x] !== x) { par[x] = par[par[x]]; x = par[x]; } return x; };
        let comps = n;
        for (const [u, v, s, mst] of edges) {
            if (mst === 1) {
                if (s < X) return false;
                const ru = find(u), rv = find(v);
                if (ru === rv) return false;
                par[ru] = rv; comps--;
            }
        }
        for (const [u, v, s, mst] of edges) {
            if (mst === 0 && s >= X) {
                const ru = find(u), rv = find(v);
                if (ru !== rv) { par[ru] = rv; comps--; }
            }
        }
        let cost = 0;
        for (const [u, v, s, mst] of edges) {
            if (mst === 0 && s < X && 2 * s >= X) {
                const ru = find(u), rv = find(v);
                if (ru !== rv) { par[ru] = rv; comps--; cost++; }
            }
        }
        return comps === 1 && cost <= k;
    };
    const cs = new Set([1]);
    for (const [u, v, s, mst] of edges) { cs.add(s); cs.add(2 * s); }
    const cands = Array.from(cs).sort((a, b) => a - b);
    let best = -1;
    let lo = 0, hi = cands.length - 1;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (feasible(cands[mid])) { best = cands[mid]; lo = mid + 1; }
        else hi = mid - 1;
    }
    return best;
};
